 1	import React, { FC, useCallback, useState } from 'react';
 2	
 3	import { Button, ButtonVariant, debounce, Tooltip } from '@patternfly/react-core';
 4	import { NodeNetworkConfigurationInterface } from '@types';
 5	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
 6	
 7	import { copyToClipboard, downloadYAML } from './utils';
 8	
 9	type InterfaceDrawerFooterProps = {
10	  selectedInterface: NodeNetworkConfigurationInterface;
11	};
12	
13	const InterfaceDrawerYAMLFooter: FC<InterfaceDrawerFooterProps> = ({ selectedInterface }) => {
14	  const { t } = useNMStateTranslation();
15	  const [copied, setCopied] = useState(false);
16	
17	  const resetCopied = useCallback(
18	    debounce(() => {
19	      setCopied(false);
20	    }, 3000),
21	    [],
22	  );
23	
24	  const onCopy = useCallback(() => {
25	    copyToClipboard(selectedInterface);
26	    setCopied(true);
27	
28	    resetCopied();
29	  }, []);
30	
31	  return (
32	    <>
33	      <Tooltip content={copied ? t('Copied') : t('Copy YAML to clipboard')}>
34	        <Button variant={ButtonVariant.primary} onClick={onCopy}>
35	          {t('Copy')}
36	        </Button>
37	      </Tooltip>
38	      <Button
39	        variant={ButtonVariant.secondary}
40	        onClick={() => downloadYAML(selectedInterface)}
41	        className="pf-u-ml-md"
42	      >
43	        {t('Download YAML')}
44	      </Button>
45	    </>
46	  );
47	};
48	
49	export default InterfaceDrawerYAMLFooter;

